#include "ca6k00402_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k00402CustomTilingData tiling;
    auto storageShape = context->GetInputShape(0);
    auto originShape = storageShape->GetOriginShape();
    const uint32_t totalLength = static_cast<uint32_t>(originShape.GetShapeSize());

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    int64_t dim = attrs->GetAttrPointer<int64_t>(0)[0];
    uint32_t ndim = static_cast<uint32_t>(originShape.GetDimNum());
    if (dim < 0) dim += ndim;
    if (dim < 0 || static_cast<uint32_t>(dim) >= ndim) {
        return ge::GRAPH_FAILED;
    }

    uint32_t reductionSize = static_cast<uint32_t>(originShape.GetDim(static_cast<uint32_t>(dim)));
    uint32_t outerSize = 1;
    for (uint32_t i = 0; i < ndim; i++) {
        if (i != static_cast<uint32_t>(dim))
            outerSize *= static_cast<uint32_t>(originShape.GetDim(i));
    }

    uint32_t blockDim = outerSize;
    if (blockDim > 24) blockDim = 24;
    if (blockDim == 0) blockDim = 1;
    context->SetBlockDim(blockDim);

    uint32_t chunkSize = (outerSize + blockDim - 1) / blockDim;
    if (chunkSize == 0) chunkSize = 1;

    tiling.totalLength = totalLength;
    tiling.outerSize = outerSize;
    tiling.reductionSize = reductionSize;
    tiling.chunkSize = chunkSize;
    tiling.blockDim = blockDim;

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

}

